 #OS4170","recurrence":"nao_recorrente","legacy_purchase_id":"","notes":"Pagamento de comissão - 6940356a6e82941d4b1ea1df","legacy_parent_transaction_id":"","legacy_bank_account_id":"696a7a606110b7df8db70dd9","legacy_parent_recurrence_id":"","legacy_org_id":"69864e74fb6fe137d3577c07","is_installment":"false","recurrence_end_date":"","installment_count":"1","status":"pago","created_at":"2026-03-10T20:59:41.976000","updated_at":"2026-03-10T20:59:41.976000","created_by":"service+cc865314-18f7-402e-b534-8a8dc7f7e16b@no-reply.base44.com"},{"legacy_financial_transaction_id":"69b0863c223baca391b3d60b","legacy_installment_id":"","type":"saida","current_installment":"1","legacy_employee_financial_record_id":"69a86ae1b9eaf102e9e6556d","category":"salarios","amount":"385.6","due_date":"2026-03-10","description":"Comissão (à vista) ANDERSON DOS SANTOS 2 OS #OS4195","recurrence":"nao_recorrente","legacy_purchase_id":"","notes":"Pagamento de comissão - 6940356a6e82941d4b1ea1df","legacy_parent_transaction_id":"","legacy_bank_account_id":"696a7a606110b7df8db70dd9","legacy_parent_recurrence_id":"","legacy_org_id":"69864e74fb6fe137d3577c07","is_installment":"false","recurrence_end_date":"","installment_count":"1","status":"pago","created_at":"2026-03-10T20:59:40.920000","updated_at":"2026-03-10T20:59:40.920000","created_by":"service+cc865314-18f7-402e-b534-8a8dc7f7e16b@no-reply.base44.com"},{"legacy_financial_transaction_id":"69b0863b95b2ac00f5993c8f","legacy_installment_id":"","type":"saida","current_installment":"1","legacy_employee_financial_record_id":"69af2608340af08a7576814c","category":"salarios","amount":"75","due_date":"2026-03-10","description":"Comissão (à vista) MOACIR DOS SANTOS OS #OS4224","recurrence":"nao_recorrente","legacy_purchase_id":"","notes":"Pagamento de comissão - 6939bc9a7dc0716bdcdaa1c4","legacy_parent_transaction_id":"","legacy_bank_account_id":"696a7a606110b7df8db70dd9","legacy_parent_recurrence_id":"","legacy_org_id":"69864e74fb6fe137d3577c07","is_installment":"false","recurrence_end_date":"","installment_count":"1","status":"pago","created_at":"2026-03-10T20:59:39.948000","updated_at":"2026-03-10T20:59:39.948000","created_by":"service+cc865314-18f7-402e-b534-8a8dc7f7e16b@no-reply.base44.com"},{"legacy_financial_transaction_id":"69b0863af55da6c71d39571a","legacy_installment_id":"","type":"saida","current_installment":"1","legacy_employee_financial_record_id":"69af260712d196cec03cddd8","category":"salarios","amount":"75","due_date":"2026-03-10","description":"Comissão (à vista) ANDERSON DOS SANTOS 2 OS #OS4224","recurrence":"nao_recorrente","legacy_purchase_id":"","notes":"Pagamento de comissão - 6940356a6e82941d4b1ea1df","legacy_parent_transaction_id":"","legacy_bank_account_id":"696a7a606110b7df8db70dd9","legacy_parent_recurrence_id":"","legacy_org_id":"69864e74fb6fe137d3577c07","is_installment":"false","recurrence_end_date":"","installment_count":"1","status":"pago","created_at":"2026-03-10T20:59:38.951000","updated_at":"2026-03-10T20:59:38.951000","created_by":"service+cc865314-18f7-402e-b534-8a8dc7f7e16b@no-reply.base44.com"},{"legacy_financial_transaction_id":"69b08639a304239d1562318c","legacy_installment_id":"","type":"saida","current_installment":"1","legacy_employee_financial_record_id":"69a6d01d6b54b8a55a3e1ea0","category":"salarios","amount":"385.6","due_date":"2026-03-10","description":"Comissão (à vista) ANDERSON DOS SANTOS 2 OS #OS4160","recurrence":"nao_recorrente","legacy_purchase_id":"","notes":"Pagamento de comissão - 6940356a6e82941d4b1ea1df","legacy_parent_transaction_id":"","legacy_bank_account_id":"696a7a606110b7df8db70dd9","legacy_parent_recurrence_id":"","legacy_org_id":"69864e74fb6fe137d3577c07","is_installment":"false","recurrence_end_date":"","installment_count":"1","status":"pago","created_at":"2026-03-10T20:59:37.955000","updated_at":"2026-03-10T20:59:37.955000","created_by":"service+cc865314-18f7-402e-b534-8a8dc7f7e16b@no-reply.base44.com"},{"legacy_financial_transaction_id":"69b086388b08499db429eb99","legacy_installment_id":"","type":"saida","current_installment":"1","legacy_employee_financial_record_id":"69a6d01dee9b9e9088173d9d","category":"salarios","amount":"385.6","due_date":"2026-03-10","description":"Comissão (à vista) MOACIR DOS SANTOS OS #OS4160","recurrence":"nao_recorrente","legacy_purchase_id":"","notes":"Pagamento de comissão - 6939bc9a7dc0716bdcdaa1c4","legacy_parent_transaction_id":"","legacy_bank_account_id":"696a7a606110b7df8db70dd9","legacy_parent_recurrence_id":"","legacy_org_id":"69864e74fb6fe137d3577c07","is_installment":"false","recurrence_end_date":"","installment_count":"1","status":"pago","created_at":"2026-03-10T20:59:36.933000","updated_at":"2026-03-10T20:59:36.933000","created_by":"service+cc865314-18f7-402e-b534-8a8dc7f7e16b@no-reply.base44.com"}]$financial_transactions$::jsonb) AS src(
    legacy_financial_transaction_id text,
    legacy_installment_id text,
    type text,
    current_installment text,
    legacy_employee_financial_record_id text,
    category text,
    amount text,
    due_date text,
    description text,
    recurrence text,
    legacy_purchase_id text,
    notes text,
    legacy_parent_transaction_id text,
    legacy_bank_account_id text,
    legacy_parent_recurrence_id text,
    legacy_org_id text,
    is_installment text,
    recurrence_end_date text,
    installment_count text,
    status text,
    created_at text,
    updated_at text,
    created_by text
  );


  INSERT INTO public.financial_transactions (
    id, organization_id, description, amount, due_date, type, status, category,
    recurrence, recurrence_end_date, parent_recurrence_id, is_installment,
    installment_count, current_installment, parent_transaction_id,
    employee_financial_record_id, bank_account_id, service_order_installment_id,
    purchase_id, service_order_id, payment_method, notes, created_at, created_by,
    updated_at, updated_by, deleted_at, deleted_by
  )
  SELECT
    uuid_generate_v5(v_namespace, 'financial_transaction:' || src.legacy_financial_transaction_id),
    organizations.id,
    LEFT(COALESCE(NULLIF(src.description, ''), 'Lancamento financeiro'), 300),
    COALESCE(NULLIF(src.amount, '')::numeric, 0),
    COALESCE(NULLIF(src.due_date, '')::date, NULLIF(src.created_at, '')::date, CURRENT_DATE),
    CASE src.type
      WHEN 'entrada' THEN 'income'
      WHEN 'saida' THEN 'expense'
      WHEN 'transferencia_entrada' THEN 'transfer_in'
      WHEN 'transferencia_saida' THEN 'transfer_out'
      ELSE 'expense'
    END,
    CASE src.status WHEN 'pago' THEN 'paid' WHEN 'cancelado' THEN 'cancelled' ELSE 'pending' END,
    CASE
      WHEN lower(src.category) = 'vendas' THEN 'sales'
      WHEN lower(src.category) LIKE 'servi%' THEN 'services'
      WHEN lower(src.category) = 'aluguel' THEN 'rent'
      WHEN lower(src.category) LIKE 'sal%' OR lower(src.category) IN ('custo com pessoal', 'prolabore') THEN 'salaries'
      WHEN lower(src.category) IN ('fornecedores', 'terceirizado') OR lower(src.category) LIKE 'pe%' THEN 'suppliers'
      WHEN lower(src.category) = 'impostos' THEN 'taxes'
      WHEN lower(src.category) = 'marketing' THEN 'marketing'
      ELSE 'other'
    END,
    CASE src.recurrence WHEN 'nao_recorrente' THEN 'non_recurring' WHEN 'mensal' THEN 'monthly' WHEN 'anual' THEN 'annual' ELSE NULL END,
    NULLIF(src.recurrence_end_date, '')::date,
    NULL,
    COALESCE(NULLIF(src.is_installment, '')::boolean, false),
    NULLIF(src.installment_count, '')::int,
    NULLIF(src.current_installment, '')::int,
    NULL,
    employee_records.id,
    bank_accounts.id,
    installments.id,
    purchases.id,
    COALESCE(installments.service_order_id, employee_records.service_order_id),
    NULL,
    NULLIF(src.notes, ''),
    COALESCE(NULLIF(src.created_at, '')::timestamptz, now()),
    NULLIF(src.created_by, ''),
    COALESCE(NULLIF(src.updated_at, '')::timestamptz, NULLIF(src.created_at, '')::timestamptz, now()),
    NULLIF(src.created_by, ''),
    NULL,
    NULL
  FROM tmp_financial_transaction_source AS src
  JOIN public.organizations AS organizations
    ON organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
  LEFT JOIN public.employee_financial_records AS employee_records
    ON employee_records.id = uuid_generate_v5(v_namespace, 'employee_financial_record:' || src.legacy_employee_financial_record_id)
  LEFT JOIN public.service_order_installments AS installments
    ON COALESCE(src.legacy_installment_id, '') <> ''
   AND installments.id = uuid_generate_v5(v_namespace, 'service_order_installment:' || src.legacy_installment_id)
  LEFT JOIN public.bank_accounts AS bank_accounts
    ON bank_accounts.id = uuid_generate_v5(v_namespace, 'bank_account:' || src.legacy_bank_account_id)
  LEFT JOIN public.purchases AS purchases
    ON purchases.id = uuid_generate_v5(v_namespace, 'purchase:' || src.legacy_purchase_id)
  WHERE src.legacy_org_id <> ''
    AND src.description <> ''
    AND src.amount <> ''
    AND src.due_date <> ''
  ON CONFLICT (id) DO UPDATE
  SET
    organization_id = EXCLUDED.organization_id,
    description = EXCLUDED.description,
    amount = EXCLUDED.amount,
    due_date = EXCLUDED.due_date,
    type = EXCLUDED.type,
    status = EXCLUDED.status,
    category = EXCLUDED.category,
    recurrence = EXCLUDED.recurrence,
    recurrence_end_date = EXCLUDED.recurrence_end_date,
    is_installment = EXCLUDED.is_installment,
    installment_count = EXCLUDED.installment_count,
    current_installment = EXCLUDED.current_installment,
    employee_financial_record_id = EXCLUDED.employee_financial_record_id,
    bank_account_id = EXCLUDED.bank_account_id,
    service_order_installment_id = EXCLUDED.service_order_installment_id,
    purchase_id = EXCLUDED.purchase_id,
    service_order_id = EXCLUDED.service_order_id,
    payment_method = EXCLUDED.payment_method,
    notes = EXCLUDED.notes,
    updated_at = EXCLUDED.updated_at,
    updated_by = EXCLUDED.updated_by,
    deleted_at = NULL,
    deleted_by = NULL;

  UPDATE public.purchases AS purchases
  SET
    financial_transaction_id = financial_transactions.id,
    updated_at = financial_transactions.updated_at,
    updated_by = financial_transactions.updated_by
  FROM tmp_financial_transaction_source AS src
  JOIN public.financial_transactions AS financial_transactions
    ON financial_transactions.id = uuid_generate_v5(v_namespace, 'financial_transaction:' || src.legacy_financial_transaction_id)
  WHERE purchases.id = uuid_generate_v5(v_namespace, 'purchase:' || src.legacy_purchase_id)
    AND COALESCE(src.legacy_purchase_id, '') <> '';

  UPDATE public.financial_transactions AS ft
  SET parent_recurrence_id = parent_ft.id
  FROM tmp_financial_transaction_source AS src
  JOIN public.financial_transactions AS parent_ft
    ON parent_ft.id = uuid_generate_v5(v_namespace, 'financial_transaction:' || src.legacy_parent_recurrence_id)
  WHERE ft.id = uuid_generate_v5(v_namespace, 'financial_transaction:' || src.legacy_financial_transaction_id)
    AND COALESCE(src.legacy_parent_recurrence_id, '') <> '';

  UPDATE public.financial_transactions AS ft
  SET parent_transaction_id = parent_ft.id
  FROM tmp_financial_transaction_source AS src
  JOIN public.financial_transactions AS parent_ft
    ON parent_ft.id = uuid_generate_v5(v_namespace, 'financial_transaction:' || src.legacy_parent_transaction_id)
  WHERE ft.id = uuid_generate_v5(v_namespace, 'financial_transaction:' || src.legacy_financial_transaction_id)
    AND COALESCE(src.legacy_parent_transaction_id, '') <> '';

  UPDATE public.service_order_installments AS installments
  SET financial_transaction_id = financial_transactions.id
  FROM tmp_financial_transaction_source AS src
  JOIN public.financial_transactions AS financial_transactions
    ON financial_transactions.id = uuid_generate_v5(v_namespace, 'financial_transaction:' || src.legacy_financial_transaction_id)
  WHERE installments.id = uuid_generate_v5(v_namespace, 'service_order_installment:' || src.legacy_installment_id)
    AND COALESCE(src.legacy_installment_id, '') <> ''
    AND COALESCE(src.legacy_financial_transaction_id, '') <> '';

  UPDATE public.employee_financial_records AS records
  SET financial_transaction_id = financial_transactions.id
  FROM tmp_financial_transaction_source AS src
  JOIN public.financial_transactions AS financial_transactions
    ON financial_transactions.id = uuid_generate_v5(v_namespace, 'financial_transaction:' || src.legacy_financial_transaction_id)
  WHERE records.id = uuid_generate_v5(v_namespace, 'employee_financial_record:' || src.legacy_employee_financial_record_id)
    AND COALESCE(src.legacy_financial_transaction_id, '') <> '';


  RAISE NOTICE 'Skipped % financial transactions without resolvable organization or required fields.', (
    SELECT count(*)
    FROM tmp_financial_transaction_source AS src
    LEFT JOIN public.organizations AS organizations
      ON organizations.id = uuid_generate_v5(v_namespace, 'organization:' || src.legacy_org_id)
    WHERE src.legacy_org_id = ''
       OR src.description = ''
       OR src.amount = ''
       OR src.due_date = ''
       OR organizations.id IS NULL
  );


END $$;